export interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronSchedule, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   7],
};

function validateRange(value: number, min: number, max: number, field: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Invalid value ${value} for field "${field}": must be between ${min} and ${max}`);
  }
}

function expandField(expr: string, field: keyof CronSchedule): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => expandField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let start = min;
    let end = max;

    if (rangeExpr !== "*") {
      if (rangeExpr.includes("-")) {
        const [lo, hi] = rangeExpr.split("-").map((n) => parseInt(n, 10));
        validateRange(lo, min, max, field);
        validateRange(hi, min, max, field);
        if (lo > hi) throw new RangeError(`Invalid range ${lo}-${hi} in field "${field}"`);
        start = lo;
        end = hi;
      } else {
        start = parseInt(rangeExpr, 10);
        validateRange(start, min, max, field);
        end = max;
      }
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) values.push(v);
    return values;
  }

  if (expr.includes("-")) {
    const [loStr, hiStr] = expr.split("-");
    const lo = parseInt(loStr, 10);
    const hi = parseInt(hiStr, 10);
    validateRange(lo, min, max, field);
    validateRange(hi, min, max, field);
    if (lo > hi) throw new RangeError(`Invalid range ${lo}-${hi} in field "${field}"`);
    return Array.from({ length: hi - lo + 1 }, (_, i) => lo + i);
  }

  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Unexpected token "${expr}" in field "${field}"`);
  }
  validateRange(value, min, max, field);
  return [value];
}

export default function parseCron(expression: string): CronSchedule {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  const schedule: CronSchedule = {
    minute:     expandField(minuteExpr, "minute"),
    hour:       expandField(hourExpr, "hour"),
    dayOfMonth: expandField(domExpr, "dayOfMonth"),
    month:      expandField(monthExpr, "month"),
    dayOfWeek:  expandField(dowExpr, "dayOfWeek"),
  };

  // Normalize: both 0 and 7 represent Sunday — collapse to 0
  const dow = schedule.dayOfWeek;
  if (dow.includes(7)) {
    schedule.dayOfWeek = [...new Set(dow.map((d) => (d === 7 ? 0 : d)))].sort((a, b) => a - b);
  }

  return schedule;
}
