    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in step: ${field}`);
    if (start < min || end > max) throw new Error(`Step range ${start}-${end} out of bounds [${min}-${max}]`);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
